protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF9: discriminator property renamed from "Discriminator" to "$type".
        // Preserve old name so existing 500K documents and direct SQL queries
        // referencing c.Discriminator continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF9: id values no longer include the discriminator prefix.
        // Preserve old "Product|123" format so existing documents remain accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

